# --- Middleware / Hooks ---
@app.before_request
def before_request():
    g.start_time = time.time()
    endpoint = request.endpoint or 'unknown'
    REQUESTS_IN_PROGRESS.labels(method=request.method, endpoint=endpoint).inc()


@app.after_request
def after_request(response):
    endpoint = request.endpoint or 'unknown'
    method = request.method

    # Calculate latency
    latency = time.time() - g.start_time

    # Record metrics
    REQUEST_COUNT.labels(
        method=method,
        endpoint=endpoint,
        status_code=response.status_code
    ).inc()

    REQUEST_LATENCY.labels(
        method=method,
        endpoint=endpoint
    ).observe(latency)

    # Track response size
    response_size = len(response.get_data())
    RESPONSE_SIZE.labels(
        method=method,
        endpoint=endpoint
    ).observe(response_size)

    # Decrement in-progress gauge
    REQUESTS_IN_PROGRESS.labels(method=method, endpoint=endpoint).dec()

    # Track errors
    if response.status_code >= 400:
        error_type = 'client_error' if response.status_code < 500 else 'server_error'
        ERROR_COUNT.labels(
            method=method,
            endpoint=endpoint,
            error_type=error_type
        ).inc()

    return response


# --- Decorator for tracking business transactions ---
def track_business_transaction(transaction_type):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            start = time.time()
            try:
                result = f(*args, **kwargs)
                BUSINESS_EVENTS_TOTAL.labels(event_type=f'{transaction_type}_success').inc()
                return result
            except Exception as e:
                BUSINESS_EVENTS_TOTAL.labels(event_type=f'{transaction_type}_failure').inc()
                raise
            finally:
                duration = time.time() - start
                BUSINESS_TRANSACTION_DURATION.labels(
                    transaction_type=transaction_type
                ).observe(duration)
        return decorated_function
    return decorator


