    # Simulate multiple user requests
    for i in range(10):
        latency = random.uniform(0.001, 0.5)
        status = random.choices([200, 201, 400, 404, 500], weights=[70, 10, 10, 7, 3])[0]

        REQUEST_COUNT.labels(
            method='GET',
            endpoint=f'simulated_endpoint_{random.randint(1, 5)}',
            status_code=status
        ).inc()

        REQUEST_LATENCY.labels(
            method='GET',
            endpoint=f'simulated_endpoint_{random.randint(1, 5)}'
        ).observe(latency)

        results.append({'latency': round(latency, 4), 'status': status})

    # Simulate DB queries
    for table in ['users', 'orders', 'products', 'sessions']:
        for query_type in ['SELECT', 'INSERT', 'UPDATE']:
            query_time = random.uniform(0.001, 0.1)
            DB_QUERY_DURATION.labels(query_type=query_type, table=table).observe(query_time)

    # Simulate business metrics
    for _ in range(5):
        ORDER_VALUE.observe(random.uniform(5.0, 1000.0))

    ACTIVE_USERS.set(random.randint(50, 500))
    QUEUE_SIZE.labels(queue_name='order_processing').set(random.randint(0, 50))
    QUEUE_SIZE.labels(queue_name='task_processing').set(random.randint(0, 30))
    QUEUE_SIZE.labels(queue_name='email_notifications').set(random.randint(0, 100))

    for event in ['login', 'logout', 'page_view', 'purchase', 'signup']:
        BUSINESS_EVENTS_TOTAL.labels(event_type=event).inc(random.randint(1, 20))

    return jsonify({
        'message': 'Traffic simulation complete',
        'simulated_requests': len(results),
        'sample_results': results[:3]
    })


